def solve(s: String): Long = {
    val n = s.length
    val prefix_L = Array.ofDim[Int](n + 1)
    val suffix_T = Array.ofDim[Int](n + 1)

    for (i <- 0 until n) {
        prefix_L(i + 1) = prefix_L(i) + (if (s(i) == 'L') 1 else 0)
    }

    for (i <- n - 1 downTo 0) {
        suffix_T(i) = suffix_T(i + 1) + (if (s(i) == 'T') 1 else 0)
    }

    var original_total = 0L
    for (i <- 0 until n) {
        if (s(i) == 'C') {
            original_total += prefix_L(i) * suffix_T(i + 1)
        }
    }

    var sum_L_gain = 0L
    for (i <- 0 until n) {
        if (s(i) == 'C') {
            sum_L_gain += suffix_T(i + 1)
        }
    }

    var sum_T_gain = 0L
    for (i <- 0 until n) {
        if (s(i) == 'C') {
            sum_T_gain += prefix_L(i)
        }
    }

    var max_C_gain = 0L
    for (i <- 0 until (n + 1)) {
        val current = prefix_L(i) * suffix_T(i)
        if (current > max_C_gain) {
            max_C_gain = current
        }
    }

    val max_gain = Math.max(sum_L_gain, Math.max(sum_T_gain, max_C_gain))
    original_total + max_gain
}
